const n=document.getElementById("mobile-menu-btn"),t=document.getElementById("mobile-menu"),o=document.getElementById("menu-icon-open"),c=document.getElementById("menu-icon-close");n.addEventListener("click",()=>{const e=!t.classList.contains("hidden");t.classList.toggle("hidden",e),o.classList.toggle("hidden",!e),c.classList.toggle("hidden",e)});const s=document.getElementById("theme-toggle");s.addEventListener("click",()=>{const e=document.documentElement.classList.toggle("dark");localStorage.setItem("theme",e?"dark":"light")});
